var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"……여긴.","JPN":"ここは……","ENG":"... Where am I?","TWN":"……這裡，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"으, 추워……","JPN":"ああ、寒い……","ENG":"Aww, cold...","TWN":"好冷……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"정신이 들었으면, 불가로 좀 붙지 그래.","JPN":"気がついたなら、焚き火の近くに来れば？","ENG":"If you're awake, come closer to the fire.","TWN":"醒了嗎？那就一起過來取暖吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"당신은…… 어째서 아직 여기 있는 거죠?","JPN":"あなたは……どうしてまだここにいるのですか？","ENG":"You... Why are you still here?","TWN":"你……怎麼還在這裡？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"보면 몰라. 불 쬐고 있잖아.","JPN":"見りゃわかるだろ。火にあたってる。","ENG":"Can't you see? I'm warming myself by the fire.","TWN":"看不出來我在取暖嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"침식체가 널 지키고 있어서 자릴 옮기지도 못하고 불을 여기에다 피워야 했다고.","JPN":"侵食体が君を守っているせいで場所を移せないから、ここで火を起こしたんだよ。","ENG":"Those C.O.s were protecting you like a treasure. I couldn't move you so I had to make a fire here.","TWN":"侵蝕體圍著你不走，搞得我也走不了，只好在這裡升火囉。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저 때문에 남아있었던 건가요?","JPN":"私のために残っていたのですか？","ENG":"Did you stay behind because of me?","TWN":"你是為了我留下來的嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"황무지의 밤은 추우니까.","JPN":"荒れ地の夜は寒いから。","ENG":"It's cold at night in the wasteland.","TWN":"曠野晚上很冷，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"불이 없으면 얼어 죽어. 체감상 침식지대는 그 추위가 더 심한 편이고.","JPN":"火がないと凍え死ぬ。経験上、侵食地帯はその寒さがさらにひどいし。","ENG":"You can easily freeze without fire. It feels colder in the Corrupted areas, too.","TWN":"沒有火的話會冷死的。而且侵蝕地區的體感溫度更低。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"절 괴물이라고 의심하지 않는 건가요?","JPN":"私を化け物だと疑わないんですか？","ENG":"Don't you think I'm a monster anymore?","TWN":"你沒有懷疑我是怪物嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그건 이제 됐어. 네가 진짜 그림자였다면 그런 식으로 맥없이 쓰러지진 않았겠지.","JPN":"それはもういいよ。君が本当にシャドウだったら、そんなふうにあっけなく倒れたりなんてしないだろ？","ENG":"No. If you were a real Shadow, you wouldn't have fallen so limply like that.","TWN":"沒事了啦，要是你真的是暗影，怎麼可能就這樣虛弱地暈過去。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"고마워요.","JPN":"ありがとうございます。","ENG":"Thank you.","TWN":"謝謝你。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"차에 있던 캔스프를 좀 꺼내 왔어. 먹고 싶으면 먹어.","JPN":"車に積んでた缶スープを持ってきた。食べたければ食べて。","ENG":"I brought this canned soup from the car. You can drink it if you want.","TWN":"這是我從車裡拿出來的罐頭湯，你想吃的話就拿去吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아, 네.","JPN":"あ、はい。","ENG":"Oh, okay.","TWN":"喔，好。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"자, 잠깐!","JPN":"ちょ、ちょっと待て！","ENG":"W-wait!","TWN":"喂，等一下！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그걸 그냥 벌컥벌컥 마시려고 하면 어떡해?","JPN":"そんながぶ飲みしようとしてどうするんだよ！","ENG":"Are you crazy? You can't gulp it like that!","TWN":"你想燙死啊？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"펄펄 끓고 있는 게 안 보이는 거야?","JPN":"沸騰してるのが見えないの？","ENG":"Can't you see it's boiling hot?","TWN":"沒看到湯正在滾嗎？！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"아.","JPN":"あっ。","ENG":"Oh.","TWN":"啊！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"죄송해요.","JPN":"すみません。","ENG":"I'm sorry.","TWN":"不好意思。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"맛이라거나…… 가끔은 아프다는 것도 느끼지 못해서요.","JPN":"味とか……時には痛いということも感じられなくて。","ENG":"I can't taste... or even feel pain.","TWN":"味覺……或是痛覺之類的，我有時候會感覺不到。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그리고 뜨거운 음식 같은 건, 정말 오랜만이라 잊고 있었어요.","JPN":"それに熱い食べ物なんて本当に久しぶりで、忘れていました。","ENG":"And I haven't had hot food for so long that I forgot how to eat it.","TWN":"而且我好久沒吃到熱騰騰的食物，久到我都忘了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"……대체 무슨 인생을 살다 온 거야, 넌.","JPN":"……いったいどんな人生を生きてきたんだよ、君は。","ENG":"What kind of life have you led so far?","TWN":"……你之前過的到底是什麼樣的生活啊？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"침식체를 길들인 걸 보니까, 어디 서커스단 출신이야?","JPN":"侵食体を手懐けてるし、どっかのサーカス団出身か？","ENG":"Seeing you can tame C.O.s, were you from a circus troupe or something?","TWN":"你可以控制侵蝕體，難道你以前是馬戲團的嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"제가 있던 곳은 지하실이었어요.","JPN":"私がいたところは地下室でした。","ENG":"I was in a basement.","TWN":"我生活的地方在地下室，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"한 번 들어간 뒤로, 바깥 출입 같은 건 할 수 없었고요.","JPN":"一度入ってからは、外へ出ることはできませんでした。","ENG":"Once I went in, I was never allowed out.","TWN":"從我踏入那個地方後就再也沒有離開過。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그리고 침식체를 움직이는 건……","JPN":"そして侵食体を動かすのは……","ENG":"And controlling C.O.s...","TWN":"至於我可以控制侵蝕體……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그 사람들은 이걸 기억 이식 실험이라 불렀어요.","JPN":"あの人たちは、これを記憶移植実験と呼んでいました。","ENG":"Those people call it a memory transplant test.","TWN":"那些人說這是一個叫作記憶移植的實驗，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"제가 이런 힘을 갖게 될 때까지 실험을 계속 해 왔거든요.","JPN":"私がこのような力を持つようになるまで、実験を続けていたんです。","ENG":"They'd constantly experimented on me until I developed this power.","TWN":"在我擁有這樣的能力前，就是一直不斷地在做實驗。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"실험? 그럼 혹시 맛을 느끼지 못하는 것도 그것 때문이야?","JPN":"実験？　じゃあもしかして味を感じないのもそのせい？","ENG":"Experimented on you? Did you lose your sense of taste because of that?","TWN":"實驗？該不會沒有味覺也是因為實驗的關係？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네, 실험의 부작용이래요.","JPN":"はい、実験の副作用だそうです。","ENG":"Yes, as a side effect.","TWN":"是，這是實驗的副作用。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"얼마 전 연구원 중 한 분이 하는 얘길 엿들었어요.","JPN":"先日、ある研究員の話を盗み聞きしました。","ENG":"I recently overheard one of the researchers talking about me.","TWN":"我之前有偷聽到研究員的對話，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"여기서 실험을 멈춰도, 부작용 때문에 몇 년을 살지 못할 거라고요.","JPN":"ここで実験を止めたとしても、副作用のせいであと数年しか生きられないって。","ENG":"He said, even if they stopped experimenting on me now, I wouldn't live longer than a few years because of the side effects.","TWN":"他說就算停止實驗，因為副作用的關係也活不了幾年。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"난민아이들이 여러 곳에 팔려간다는 건 들었지만 그런 짓까지……","JPN":"難民の子どもたちがいろんなところに売られているのは聞いてたけど、そんなひどい目にあっていたなんて……","ENG":"I heard child refugees were sold to various places, and that's unimaginable.","TWN":"我是有聽說過難民村的孩子被賣到別的地方去，沒想到竟然有這麼離譜的事……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"미안. 괜한 걸 물어봤네.","JPN":"ごめん。余計なことを聞いた。","ENG":"Sorry. I shouldn't have asked.","TWN":"抱歉，問你這些事。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"괜찮아요. 다 지난 일이니까.","JPN":"大丈夫です。もう過ぎたことですから。","ENG":"Don't worry. It's all in the past now.","TWN":"沒關係，都過去了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"동생들이 행복해하는 모습을 다시 볼 수만 있다면…… 그보다 큰 건 바라지 않아요.","JPN":"妹たちの幸せそうな顔がもう一度見れたら……それ以上の望みはありません。","ENG":"All I want now is to see my little sisters again and how happy they are.","TWN":"我現在最大的心願……就是希望能再次看到妹妹們幸福的模樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"동생……","JPN":"妹……","ENG":"Your little sisters...","TWN":"妹妹……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그러고 보니 동생들을 만나기 위해 국경을 나선다고 했었지.","JPN":"そういえば、あの子たちに会わないとって言ってたよね。\\nあの子たちが妹ってことか。","ENG":"Now that I think of it, you said you were going to the national border to see them.","TWN":"這麼說來，你剛有說穿越國境是要去找妹妹對吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그럼 동생들은 이미 그로니아를 떠난 거야?","JPN":"じゃあ妹たちはもうグロニアを去ったの？","ENG":"Are they out of Gronia already?","TWN":"所以妹妹們都已經離開格羅尼雅囉？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네, 그라운드 원에 무사히 정착한 것 같아요. 위탁을 맡아주신 분도 좋은 사람이고요.","JPN":"はい、グラウンド・ワンに無事落ち着けたようです。引き受けてくれた方もいい人ですし。","ENG":"Yes, and I think they've safely settled down in Ground One. Their caretaker is a good man.","TWN":"是的，他們都已經安全抵達Ｇ1了，接受委託的人也是個好人。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그거…… 잘됐네.","JPN":"それは……よかった。","ENG":"That's... good for them.","TWN":"喔喔……那就好。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그런데 그게 어떻게 가능했던 거야? 그라운드 원이란 데, 여기서 아주 멀잖아?","JPN":"ところでどうやってそんなことしたんだ？　グラウンド・ワンって、ここからすごく遠いだろう？","ENG":"But how was it possible? Ground One is really far away from here.","TWN":"不過怎麼可能呢？Ｇ1離這裡不是很遠嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"저는 가끔 꿈에서 힌트를 얻거든요.","JPN":"私はたまに、夢からヒントを得るんです。","ENG":"Sometimes I get clues from my dreams.","TWN":"我偶爾會從夢裡得到啟示，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그 아이들을 그곳으로 보내면 분명 안전할 거라는 확신이 들었죠.","JPN":"あの子たちをそこに送れば、きっと安全だと確信したんです。","ENG":"I knew that my girls would be safe if I just got them there somehow.","TWN":"就是把孩子們送到那裡一定會很安全的確據。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"그래서 어른들 몰래 그 아이들이 가게 될 곳의 주소를 바꿨어요.","JPN":"それで大人たちには内緒で、あの子たちのお届け先の住所を変えました。","ENG":"So, I changed the address of their destination secretly.","TWN":"所以我就瞞著大人，偷偷改掉孩子們原本要去的地址。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"아깐 실험이라더니…… 이젠 꿈이라고?","JPN":"さっきは実験だとか言ってたけど……今度は夢だって？","ENG":"First, you said experiments, and now... dreams?","TWN":"你剛剛說什麼實驗……現在又說什麼夢？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"들으면 들을수록 뭐가 뭔지 모르겠네.","JPN":"聞けば聞くほど、何が何だかわからないな。","ENG":"The more I listen to you, the more I'm confused.","TWN":"我真是越聽越黑人問號。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"넌 좋겠어. 이젠 너만 여길 떠나면 될 테니까.","JPN":"君はいいな。もう君だけがここを離れればいいんだろ。","ENG":"I'm envious of you, though. All you need now is just to get yourself out of here.","TWN":"你就好了，可以離開這裡去和妹妹們團圓。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"당신도 동생이 있다고 했었죠.","JPN":"あなたも弟さんがいると言っていましたね。","ENG":"You said you have a brother.","TWN":"你說你也有弟弟對吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"함께 떠날 수는 없는 건가요?","JPN":"一緒に出ていくことはできないんですか？","ENG":"Can't you leave with him?","TWN":"你不和我一起離開嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"글쎄.","JPN":"さあね。","ENG":"Well...","TWN":"不。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"나도 이 나라가 살기 좋은 곳이 아니란 걸 알지만, 아직 떠날 생각은 없어.","JPN":"僕だってこの国が住みやすい場所ではないことぐらい知ってるけど、まだ去るつもりはない。","ENG":"I know this country is not a good place to live in, but I have no intention of leaving it, just yet.","TWN":"我也知道這裡並不適合居住，但我沒想過要離開。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"내 고향이니까. 도망치기보단 내 손으로 이곳을 사람들이 살 만한 곳으로 만들고 싶어.","JPN":"僕の故郷だから。逃げるよりも自分の手で、ここを人が住みやすい場所にしたいんだ。","ENG":"This is my homeland. Instead of running away, I want to make it livable again for my people.","TWN":"因為這裡是我的家鄉，與其逃離這裡，我更希望我能夠親手將這裡改造成適合居住的地方！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"지금은 침식체가 들끓는 내전뿐인 나라지만……. 노력하다 보면 언젠가 평화로워지겠지.","JPN":"今は侵食体が湧き続ける内戦ばかりの国だけど……努力すれば、いつか平和になると思う。","ENG":"For now, it's rife with civil war and C.O.s, but who knows? Maybe it'll become peaceful again one day.","TWN":"雖然現在是個侵蝕體氾濫陷入內戰的國家……但只要努力，我相信會有和平的那一天到來。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"처음엔 너한테 부끄러운 모습을 보이긴 했지만, 그 반군들이 하던 짓을 똑같이 한다는 건 아냐.","JPN":"はじめは君に恥ずかしい姿を見せたけど、あの反乱軍たちと同じようなことはしない。","ENG":"I know I acted like a coward in the beginning, but I'm not going to do the same as the rebels.","TWN":"雖然你認識我時，我和那些叛軍混在一起，但我和那些叛軍不一樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"반군들은 평화 따위에 관심없어. 남들한테서 하나라도 더 뺏으려고 혈안이 되어 있지.","JPN":"反乱軍は平和なんかに興味ないんだ。他人から一つでも多く奪おうと血眼になってる。","ENG":"Peace isn't what they really want. They only want to steal as many as possible from others.","TWN":"叛軍不在乎和平，他們滿腦子只想著掠奪。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"그냥…….. 자기들 분노를 쏟아내고 욕심만 채우기 바쁠 뿐이야.","JPN":"ただ……自分たちの怒りをぶちまけて、欲を満たすのに忙しいだけさ。","ENG":"They're just looking for ways to release their anger and satisfy their greed.","TWN":"他們……就只是一群利慾薰心的人。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"내가 그걸 바꿀 거야.","JPN":"僕がそれを変えてやる。","ENG":"I want to change that.","TWN":"但我要改變這樣的世界！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"꿈 같은 얘기긴 하지만.","JPN":"夢のような話だけどね。","ENG":"I know, it sounds like wishful thinking.","TWN":"雖然聽起來有點不切實際。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"잘 될 거예요.","JPN":"うまくいくと思いますよ。","ENG":"You can do it.","TWN":"我相信你可以的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"…… 말이라도 고맙네.","JPN":"……お世辞でもありがたいね。","ENG":"... Thank you for saying that.","TWN":"……謝謝你的安慰。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"이쪽으로 가면 50호선 고속도로가 나올 거야.","JPN":"こっちの方に行けば50号線高速道路に行ける。","ENG":"Head this way, and you'll reach I-50.","TWN":"你往這裡走就會看到50號線高速公路了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"아까 말해준 대로, 길이 헷갈린다면 해의 위치를 보면 돼.","JPN":"さっき言ったとおり、道がわからなくなったら太陽の位置を見ればいいよ。","ENG":"Like I told you earlier, if you don't know where you're going, check the location of the sun.","TWN":"萬一迷路的話，只要看海的位置就可以找到路。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"네, 고마웠어요.","JPN":"はい、ありがとうございました。","ENG":"Okay, thank you.","TWN":"好，謝謝你。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUCID_BARCODE_NULL_NULL","text":{"KOREA":"이제 돌아가는 건가요?","JPN":"もう戻るのですか？","ENG":"Are you going back now?","TWN":"你要回去了嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"가야지.","JPN":"戻らないと。","ENG":"I should.","TWN":"要回去啦～"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"동생이 기다리고 있으니까.","JPN":"弟が待ってるから。","ENG":"My brother's waiting for me.","TWN":"弟弟在等著我呢。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCID_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOY_NPC_REVELA_NAMED","text":{"KOREA":"너도, 네 동생들과 다시 만나길 바라.","JPN":"君が君の妹たちとまた会えることを願ってるよ。","ENG":"I hope you'll reunite with your sisters.","TWN":"祝你順利和妹妹們團圓。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};